$tempDir = "$env:TEMP\chrome-debug-profile"

# Remove old temp profile if exists (will fail if Chrome is using it, which is fine)
Remove-Item -Path $tempDir -Recurse -Force -ErrorAction SilentlyContinue

try {
    $proc = Start-Process -FilePath $chromePath -ArgumentList "--remote-debugging-port=9222", "--user-data-dir=$tempDir", "about:blank" -PassThru
    Write-Host "Chrome PID: $($proc.Id)"
    Start-Sleep -Seconds 3

    if (-not $proc.HasExited) {
        Write-Host "Chrome is running"
    } else {
        Write-Host "Chrome exited with code: $($proc.ExitCode)"
    }

    # Check if port is listening
    $conn = Get-NetTCPConnection -LocalPort 9222 -ErrorAction SilentlyContinue
    if ($conn) {
        Write-Host "Port 9222 is LISTENING"
    } else {
        Write-Host "Port 9222 NOT listening"
    }
} catch {
    Write-Host "Error: $_"
}

